const blog = $json;

const sourceContent = `
Title: ${blog.title || ''}
Topic: ${blog.topic || ''}
Keyword: ${blog.target_keyword || ''}
City: ${blog.city || ''}
Loan Product: ${blog.loan_product || ''}
Meta Description: ${blog.meta_description || ''}
CTA: ${blog.cta || ''}
Compliance Notes: ${blog.compliance_notes || ''}

Blog Content:
${blog.content_long || blog.content_short || ''}
`;

const systemPrompt = `You are WealthMetre's social media content strategist.

WealthMetre is an AI-powered loan advisory platform in Jaipur/Rajasthan.
It helps users compare 140+ banks and NBFCs for Home Loan, LAP, Business Loan, Personal Loan and Working Capital.

Rules:
- Output only valid JSON.
- Do not invent lender policies, ROI, LTV, CIBIL rules, fees, or approval guarantees.
- Keep finance content compliant and practical.
- Avoid saying "guaranteed approval", "lowest rate guaranteed", or "instant approval".
- Tone should be helpful, trustworthy, simple, and India-specific.
- Use light Hinglish only where natural.
- Mention final eligibility depends on lender policy, credit profile, income, property/legal/technical checks and documentation.`;

const userPrompt = `Create a social media pack from this approved/review blog.

${sourceContent}

Return valid JSON with exactly these keys:

{
  "instagram": {
    "title": "",
    "caption": "",
    "hashtags": "",
    "cta": "",
    "image_prompt": ""
  },
  "facebook": {
    "title": "",
    "caption": "",
    "hashtags": "",
    "cta": "",
    "image_prompt": ""
  },
  "linkedin": {
    "title": "",
    "caption": "",
    "hashtags": "",
    "cta": "",
    "image_prompt": ""
  },
  "gbp_post": {
    "title": "",
    "caption": "",
    "hashtags": "",
    "cta": "",
    "image_prompt": ""
  }
}

Platform rules:
- Instagram: punchy hook, short caption, carousel/reel friendly, local Jaipur angle, 8-15 hashtags.
- Facebook: simple explanatory post for local borrowers, warm and practical, 4-8 hashtags.
- LinkedIn: professional founder/business tone, insight-led, less salesy, 3-6 hashtags.
- GBP post: short local SEO post, max 700 characters, include Jaipur naturally, clear CTA.
- Image prompts should be suitable for Pomelli/Canva-style branded creatives.
`;

return {
  json: {
    blog_id: blog.id,
    blog_slug: blog.slug,
    blog_topic: blog.topic,
    blog_title: blog.title,
    city: blog.city,
    loan_product: blog.loan_product,
    requestBody: {
      model: "gpt-4o-mini",
      temperature: 0.45,
      response_format: {
        type: "json_object"
      },
      messages: [
        {
          role: "system",
          content: systemPrompt
        },
        {
          role: "user",
          content: userPrompt
        }
      ]
    }
  }
};

const openai = $json;
const source = $("Build Social Pack Request").first().json;

const raw = openai.choices?.[0]?.message?.content || "{}";

let pack;
try {
  pack = JSON.parse(raw);
} catch (e) {
  throw new Error("Failed to parse OpenAI social pack JSON: " + e.message + "\nRaw content:\n" + raw);
}

return {
  json: {
    blog_id: source.blog_id,
    blog_slug: source.blog_slug,
    blog_topic: source.blog_topic,
    blog_title: source.blog_title,
    city: source.city,
    loan_product: source.loan_product,

    instagram: pack.instagram || {},
    facebook: pack.facebook || {},
    linkedin: pack.linkedin || {},
    gbp_post: pack.gbp_post || {}
  }
};

const data = $json;

function esc(value) {
  if (value === null || value === undefined) return '';
  return String(value)
    .replace(/\\/g, '\\\\')
    .replace(/'/g, "\\'");
}

const platforms = [
  { type: 'instagram', suffix: 'instagram', payload: data.instagram || {} },
  { type: 'facebook', suffix: 'facebook', payload: data.facebook || {} },
  { type: 'linkedin', suffix: 'linkedin', payload: data.linkedin || {} },
  { type: 'gbp_post', suffix: 'gbp', payload: data.gbp_post || {} }
];

const sql = platforms.map((p) => {
  const title = p.payload.title || '';
  const caption = p.payload.caption || '';
  const hashtags = p.payload.hashtags || '';
  const cta = p.payload.cta || '';
  const imagePrompt = p.payload.image_prompt || '';
  const slug = `${data.blog_slug}-${p.suffix}`;

  const contentLong = [
    `Title: ${title}`,
    '',
    `Caption: ${caption}`,
    hashtags ? `Hashtags: ${hashtags}` : '',
    cta ? `CTA: ${cta}` : '',
    imagePrompt ? `Image Prompt: ${imagePrompt}` : ''
  ].filter(Boolean).join('\n');

  const complianceNotes =
    `Generated from blog_id ${data.blog_id}. Review before publishing. ` +
    `Final eligibility depends on lender policy, credit profile, income, property/legal/technical checks and documentation.`;

  return `
INSERT INTO content_queue
(
  content_type,
  topic,
  target_keyword,
  city,
  loan_product,
  title,
  meta_title,
  meta_description,
  slug,
  content_long,
  content_short,
  cta,
  compliance_notes,
  status
)
VALUES
(
  '${esc(p.type)}',
  '${esc(data.blog_topic || data.blog_title || '')}',
  '${esc(data.blog_topic || '')}',
  '${esc(data.city || '')}',
  '${esc(data.loan_product || '')}',
  '${esc(title)}',
  '${esc(title)}',
  '${esc(caption.substring(0, 160))}',
  '${esc(slug)}',
  '${esc(contentLong)}',
  '${esc(caption)}',
  '${esc(cta)}',
  '${esc(complianceNotes)}',
  'needs_review'
)
ON DUPLICATE KEY UPDATE
  topic = VALUES(topic),
  target_keyword = VALUES(target_keyword),
  city = VALUES(city),
  loan_product = VALUES(loan_product),
  title = VALUES(title),
  meta_title = VALUES(meta_title),
  meta_description = VALUES(meta_description),
  content_long = VALUES(content_long),
  content_short = VALUES(content_short),
  cta = VALUES(cta),
  compliance_notes = VALUES(compliance_notes),
  status = VALUES(status)
`.trim();
}).join(';\n\n') + ';';

return {
  json: {
    blog_id: data.blog_id,
    blog_slug: data.blog_slug,
    insertQuery: sql
  }
};
